/**
 * Drift Detector — integrity module
 *
 * AUTO-GENERATED by Phoenix VCS
 * Detects drift between expected and actual file hashes.
 */

export type DriftLabel = 'promote_to_requirement' | 'waiver' | 'temporary_patch' | null;

export interface DriftResult {
  file: string;
  drifted: boolean;
  label: DriftLabel;
}

export interface DriftEvent {
  file: string;
  expectedHash: string;
  actualHash: string;
  drifted: boolean;
  label: DriftLabel;
  timestamp: number;
}

export class DriftDetector {
  private events: DriftEvent[] = [];

  checkDrift(filePath: string, expectedHash: string, actualHash: string): DriftResult {
    const drifted = expectedHash !== actualHash;
    let label: DriftLabel = null;

    if (drifted) {
      // Classify the drift based on hash distance heuristics
      const hashPrefix = actualHash.slice(0, 4);
      const expectedPrefix = expectedHash.slice(0, 4);

      if (hashPrefix === expectedPrefix) {
        label = 'temporary_patch';
      } else if (actualHash.length !== expectedHash.length) {
        label = 'waiver';
      } else {
        label = 'promote_to_requirement';
      }
    }

    const event: DriftEvent = {
      file: filePath,
      expectedHash,
      actualHash,
      drifted,
      label,
      timestamp: Date.now(),
    };
    this.events.push(event);

    return { file: filePath, drifted, label };
  }

  getEvents(): DriftEvent[] {
    return [...this.events];
  }

  getDriftCount(): number {
    return this.events.filter(e => e.drifted).length;
  }
}

export function createDriftDetector(): DriftDetector {
  return new DriftDetector();
}

